const raw = ($input.item.json.raw_text || '').toUpperCase();
const clean = raw.replace(/[^A-Z0-9\s]/g, ' ').replace(/\s+/g, ' ').trim();
const interactive = $input.item.json.button_id || $input.item.json.list_id || '';
return { 
  ...($input.item.json), 
  text: clean, 
  action: interactive.toUpperCase(),
  timestamp: Date.now()
};

const dbResult = $input.all()[0]?.json || {};
const phone = $input.first().json.from;
const now = Date.now();

let session = {
  phone: phone,
  table: null,
  cart: [],
  customer_name: $input.first().json.contact_name,
  last_seen: now,
  session_started: now,
  total_orders: 0,
  preferences: {}
};

if (dbResult.phone) {
  const expired = (now - new Date(dbResult.last_seen).getTime()) > 900000;
  if (!expired) {
    session = {
      ...dbResult,
      cart: JSON.parse(dbResult.cart || '[]'),
      preferences: JSON.parse(dbResult.preferences || '{}'),
      last_seen: now
    };
  } else {
    session.total_orders = dbResult.total_orders || 0;
  }
}

return { 
  ...$input.first().json, 
  session: session,
  is_new_session: !dbResult.phone || (now - new Date(dbResult.last_seen).getTime()) > 900000
};

