  return { 
    ...$input.item.json, 
    error: 'INVALID_TABLE', 
    error_msg: 'вќЊ Invalid table number.\n\nPlease send a number between 1-' + ($env.MAX_TABLES || '200')
  };
}

const tableNum = parseInt(match[1]);
const maxTables = parseInt($env.MAX_TABLES || '200');

if (tableNum < 1 || tableNum > maxTables) {
  return { 
    ...$input.item.json, 
    error: 'TABLE_OUT_RANGE', 
    error_msg: `вќЊ Table must be between 1-${maxTables}`
  };
}

const session = $input.item.json.session;
session.table = tableNum.toString();
session.table_set_at = Date.now();

return { 
  ...$input.item.json, 
  session: session,
  table_number: tableNum
};

