const orders = $input.all();

if (!orders.length || !orders[0].json.order_id) {
  return [{
    json: {
      ...$input.first().json,
      status_text: 'вќЊ No recent orders found.\n\nPlace your first order!\nвЂў Type MENU to start'
    }
  }];
}

const order = orders[0].json;

const statusEmoji = {
  'pending_payment': 'рџ’і',
  'paid': 'вњ…',
  'preparing': 'рџ‘ЁвЂЌрџЌі',
  'ready': 'рџ””',
  'served': 'вњЁ',
  'cancelled': 'вќЊ'
};

const statusText = {
  'pending_payment': 'Awaiting Payment',
  'paid': 'Payment Received',
  'preparing': 'Being Prepared',
  'ready': 'Ready to Serve',
  'served': 'Served',
  'cancelled': 'Cancelled'
};

const emoji = statusEmoji[order.status] || 'рџ“‹';
const status = statusText[order.status] || order.status;

const eta = order.estimated_time ? `\nвЏ±пёЏ ETA: ${order.estimated_time} mins` : '';

const paymentNote = order.status === 'pending_payment' ? '\n\nвљ пёЏ Please complete payment\nType: PAID after paying' : '';

const text = `${emoji} *Order Status*\n\nрџ“‹ Order: ${order.order_id}\nрџЄ‘ Table: ${order.table_number}\nрџ’° Total: в‚№${parseFloat(order.total).toFixed(2)}\n\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\nStatus: ${status}${eta}\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ${paymentNote}\n\nрџ’Ў We'll notify you when ready!`;

return [{
  json: {
    ...$input.first().json,
    status_text: text,
    current_status: order.status
  }
}];

const orders = $input.all().map(i => i.json);

if (!orders.length) {
  return [{
    json: {
      ...$input.first().json,
      history_text: 'рџ“њ *Order History*\n\nNo orders yet!\n\nStart ordering:\nвЂў Type MENU\nвЂў Type POPULAR'
    }
  }];
}

let text = 'рџ“њ *Order History*\nв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓв”Ѓ\n\n';

orders.forEach((order, idx) => {
  const date = new Date(order.created_at);
  const dateStr = date.toLocaleDateString('en-IN');
  const timeStr = date.toLocaleTimeString('en-IN', { hour: '2-digit', minute: '2-digit' });

  text += `${idx + 1}. Order ${order.order_id}\n`;
  text += `   рџ“… ${dateStr} ${timeStr}\n`;
  text += `   рџЄ‘ Table ${order.table_number}\n`;
  text += `   рџ’° в‚№${parseFloat(order.total).toFixed(2)}\n`;
  text += `   Status: ${order.status}\n\n`;
});

text += 'рџ’Ў Type STATUS for latest order';

return [{
  json: {
    ...$input.first().json,
    history_text: text
  }
}];

const text = $input.item.json.text;
const match = text.match(/^(?:REMOVE|DELETE)\s+([A-Z]+\d+)/i);

if (!match) {
  return { 
    ...$input.item.json, 
    error: 'INVALID_REMOVE', 
    error_msg: 'вќЊ Invalid format.\n\nUse: REMOVE B1' 
  };
}

const code = match[1].toUpperCase();
const session = $input.item.json.session;
const itemIndex = session.cart.findIndex(i => i.code === code);

if (itemIndex === -1) {
  return { 
    ...$input.item.json, 
    error: 'ITEM_NOT_FOUND', 
    error_msg: `вќЊ ${code} not in cart.\n\nType CART to see items` 
  };
}

const removed = session.cart.splice(itemIndex, 1)[0];

return { 
  ...$input.item.json, 
  session: session,
  removed_item: removed
};
